use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;

struct UploadState {
    current_file: String,
    progress: f32,
    is_scanning: bool,
    total_files: usize,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let state = Arc::new(Mutex::new(UploadState {
        current_file: String::from("setup.txt"),
        progress: 0.0,
        is_scanning: false,
        total_files: 3,
    }));

    let display_state = Arc::clone(&state);
    let updater_handle = thread::spawn(move || {
        for i in 1..=5 {
            thread::sleep(Duration::from_millis(20));
            let mut state = display_state.lock().unwrap();
            if i < 4 {
                state.progress += 0.1;
            } else {
                state.progress = 1.0;
            }
        }
    });

    let scanner_handle = Arc::clone(&state);
    let scanner_thread = thread::spawn(move || {
        for _ in 0..3 {
            thread::sleep(Duration::from_millis(50));
            {
                let mut state = scanner_handle.lock().unwrap();
                state.is_scanning = true;
            }
            thread::sleep(Duration::from_millis(100));
            {
                let mut state = scanner_handle.lock().unwrap();
                state.is_scanning = false;
            }
        }
    });

    thread::sleep(Duration::from_secs(2));
    println!("Final State: {:?}", state.lock().unwrap());

    updater_handle.join().unwrap();
    scanner_thread.join().unwrap();

    Ok(())
}

use std::io::{self, Write};
use std::time::Duration;
use std::thread;

struct DeviceState {
    input_a: bool,
    input_b: bool,
    output_reg: u32,
}

impl Default for DeviceState {
    fn default() -> Self {
        DeviceState {
            input_a: false,
            input_b: false,
            output_reg: 0xDEADBEEF,
        }
    }
}

fn main() -> io::Result<()> {
    let mut state = DeviceState::default();
    println!("Simulating device register writes...");

    for cycle in 1..=3 {
        state.input_a = (cycle % 2) == 0;
        state.input_b = ((cycle + 1) % 2) == 0;

        let new_output = if state.input_a && state.input_b {
            0xCAFEBABE
        } else {
            state.output_reg & !((1 << cycle) - 1) | ((cycle as u32) << 8)
        };
        state.output_reg = new_output;

        print!("Cycle {} processed: Input A={}, Input B={}. New Register Value: 0x{:X}r", 
                cycle, state.input_a, state.input_b, state.output_reg);
        io::stdout().flush()?;
        thread::sleep(Duration::from_millis(500));
    }

    println!("nSimulation complete. Final State: 0x{:X}", state.output_reg);
    Ok(())
}

use std::collections::HashMap;
use std::time::{Duration, Instant};
use rand::seq::SliceRandom;

struct Process {
    pid: u32,
    name: String,
    is_active: bool
}

impl Process {
    fn new(pid: u32, name: &str) -> Self {
        Process { pid, name: name.to_string(), is_active: true }
    }

    fn check_status(&self) -> &'static str {
        if self.is_active {
            "Running"
        } else {
            "Terminated"
        }
    }

    fn terminate(&mut self) {
        if self.is_active {
            println!("Simulating termination for PID: {}", self.pid);
            self.is_active = false;
        }
    }
}

struct ProcessManager {
    processes: HashMap<u32, Process>
}

impl ProcessManager {
    fn new() -> Self {
        ProcessManager {
            processes: HashMap::new()
        }
    }

    fn add_process(&mut self, process: Process) {
        let pid = process.pid;
        self.processes.insert(pid, process);
    }

    fn simulate_failure_randomly(&mut self) -> u32 {
        if self.processes.is_empty() {
            return 0;
        }
        let mut rng = rand::thread_rng();
        let pids: Vec<u32> = self.processes.keys().cloned().collect();
        let target_pid = *pids.choose(&mut rng).unwrap();
        if let Some(process) = self.processes.get_mut(&target_pid) {
            process.terminate();
            return target_pid;
        }
        0
    }

    fn report_status(&self) {
        println!("n--- System Status Report ---");
        for (pid, process) in &self.processes {
            println!("PID: {:<5} | Name: {:<10} | Status: {}", pid, process.name, process.check_status());
        }
        println!("----------------------------n");
    }
}

fn main() {
    let mut manager = ProcessManager::new();
    manager.add_process(Process::new(100, "SystemInit"));
    manager.add_process(Process::new(205, "WebServer"));
    manager.add_process(Process::new(312, "WorkerTask"));

    println!("Starting Chaos Agent Simulation...");
    manager.report_status();

    for i in 1..=3 {
        std::thread::sleep(Duration::from_millis(500));
        let failed_pid = manager.simulate_failure_randomly();
        println!("n[Tick {}] Attempted failure on PID: {}", i, failed_pid);
        manager.report_status();
    }
}

use std::io::{self, Write};
use std::thread;
use std::time::Duration;

struct DashboardState {
    status_message: String,
    counter: u32,
}

impl DashboardState {
    fn new() -> Self {
        DashboardState {
            status_message: "Initializing secure process...".to_string(),
            counter: 0,
        }
    }

    fn update(&mut self) {
        self.counter += 1;
        if self.counter % 20 == 0 {
            self.status_message = format!("Computation step {} complete.", self.counter / 20);
        } else if self.counter > 50 {
            self.status_message = "Process finished successfully.".to_string();
        }
    }

    fn render(&self) -> io::Result<()> {
        let mut stdout = io::stdout();
        print!("r[STATUS] {}
", self.status_message);
        write!(&mut stdout, "[COUNTER] {}r", self.counter)?;
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let mut state = DashboardState::new();
    for _i in 0..100 {
        state.update();
        state.render()?;
        thread::sleep(Duration::from_millis(50));
    }
    println!("nDashboard rendering complete.");
    Ok(())
}
